// Extract and store variables for use throughout the workflow
const item = $input.first().json;

return [{
  json: {
    execution_id: item.execution_id,
    callback_url: item.callback_url || null,
    scene_videos: item.scene_videos,
    transition_type: item.config?.transition_type || 'crossfade',
    transition_duration: item.config?.transition_duration || 0.5,
    output_format: item.config?.output_format || 'mp4',
    output_resolution: item.config?.output_resolution || '1080p',
    audio_normalize: item.config?.audio_normalize !== false,
    temp_dir: `/tmp/n8n/${item.execution_id}`,
    s3_output_path: `${item.execution_id}/final/output.${item.config?.output_format || 'mp4'}`
  }
}];

// Sort scene videos by order and compute totals
const vars = $input.first().json;
const videos = vars.scene_videos;

const sorted = [...videos].sort((a, b) => a.order - b.order);

return [{
  json: {
    sorted_videos: sorted,
    total_videos: sorted.length,
    total_duration: sorted.reduce((acc, v) => acc + v.duration_seconds, 0)
  }
}];

// Download all scene videos to temp directory with retry logic
const videos = $('Sort Videos').first().json.sorted_videos;
const tempDir = $('Set Variables').first().json.temp_dir;
const downloadedPaths = [];

for (let i = 0; i < videos.length; i++) {
  const video = videos[i];
  const localPath = `${tempDir}/scene_${String(video.scene_id).padStart(2, '0')}.mp4`;

  let downloaded = false;
  let lastError = null;

  // Retry up to 3 times per video
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      if (attempt > 0) {
        await new Promise(resolve => setTimeout(resolve, 2000 * Math.pow(2, attempt)));
      }

      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: video.video_url,
        encoding: 'arraybuffer',
        timeout: 120000
      });

      const fs = require('fs');
      fs.writeFileSync(localPath, Buffer.from(response));

      downloaded = true;
      break;
    } catch (err) {
      lastError = err;
    }
  }

  if (!downloaded) {
    throw new Error(`Failed to download scene ${video.scene_id} after 3 attempts: ${lastError?.message || 'Unknown error'}`);
  }

  downloadedPaths.push({
    scene_id: video.scene_id,
    local_path: localPath,
    duration: video.duration_seconds
  });
}

return [{
  json: {
    downloaded_videos: downloadedPaths,
    temp_dir: tempDir
  }
}];

// Generate concat.txt file for FFmpeg simple concatenation
const videos = $('Download All Videos').first().json.downloaded_videos;
const tempDir = $('Download All Videos').first().json.temp_dir;
const concatFilePath = `${tempDir}/concat.txt`;
const audioNormalize = $('Set Variables').first().json.audio_normalize;

const concatContent = videos
  .map(v => `file '${v.local_path}'`)
  .join('\n');

const fs = require('fs');
fs.writeFileSync(concatFilePath, concatContent);

return [{
  json: {
    concat_file: concatFilePath,
    video_count: videos.length
  }
}];

// Build and execute FFmpeg crossfade/fade transition command
const videos = $('Download All Videos').first().json.downloaded_videos;
const tempDir = $('Set Variables').first().json.temp_dir;
const transitionDuration = $('Set Variables').first().json.transition_duration;
const transitionType = $('Set Variables').first().json.transition_type;
const audioNormalize = $('Set Variables').first().json.audio_normalize;
const outputPath = `${tempDir}/output.mp4`;

// Map transition_type to FFmpeg xfade transition name
const transitionMap = {
  'crossfade': 'fade',
  'fade': 'fade',
  'wipe': 'wipeleft',
  'slide': 'slideright'
};
const xfadeTransition = transitionMap[transitionType] || 'fade';

if (videos.length === 1) {
  // Single video - just copy it
  const fs = require('fs');
  fs.copyFileSync(videos[0].local_path, outputPath);
  const stats = fs.statSync(outputPath);
  return [{
    json: {
      output_path: outputPath,
      file_size: stats.size,
      transition_type: transitionType
    }
  }];
}

// Build complex filter for xfade transitions
let filterComplex = '';

for (let i = 1; i < videos.length; i++) {
  const prevOutput = i === 1 ? '[0:v]' : `[v${i-1}]`;
  const currentInput = `[${i}:v]`;
  const outputLabel = i === videos.length - 1 ? '[vout]' : `[v${i}]`;
  const offset = videos.slice(0, i).reduce((acc, v) => acc + v.duration - transitionDuration, 0);

  filterComplex += `${prevOutput}${currentInput}xfade=transition=${xfadeTransition}:duration=${transitionDuration}:offset=${offset}${outputLabel};`;
}

// Audio concat
const audioInputs = videos.map((_, i) => `[${i}:a]`).join('');
filterComplex += `${audioInputs}concat=n=${videos.length}:v=0:a=1[aout]`;

// Build input arguments
const inputs = videos.map(v => `-i "${v.local_path}"`).join(' ');

// Add audio normalization filter if enabled
const audioFilter = audioNormalize ? ' -af loudnorm' : '';

const ffmpegCommand = `ffmpeg -y ${inputs} -filter_complex "${filterComplex}" -map "[vout]" -map "[aout]" -c:v libx264 -preset medium -crf 23 -c:a aac -b:a 128k${audioFilter} "${outputPath}"`;

const { execSync } = require('child_process');
try {
  execSync(ffmpegCommand, { maxBuffer: 50 * 1024 * 1024 });
} catch (error) {
  throw new Error(`FFmpeg crossfade failed: ${error.message}`);
}

const fs = require('fs');
const stats = fs.statSync(outputPath);

return [{
  json: {
    output_path: outputPath,
    file_size: stats.size,
    transition_type: transitionType
  }
}];

// Merge output from either concat path (basic or crossfade)
const item = $input.first().json;

// From basic concat path, output_path is in temp_dir
const tempDir = $('Set Variables').first().json.temp_dir;
let outputPath = item.output_path || `${tempDir}/output.mp4`;
let fileSize = item.file_size || 0;

// If we came from basic concat, get file size
if (!fileSize) {
  try {
    const fs = require('fs');
    const stats = fs.statSync(outputPath);
    fileSize = stats.size;
  } catch (e) {
    // File stats failed, continue without size
  }
}

return [{
  json: {
    output_path: outputPath,
    file_size: fileSize
  }
}];

// Determine final output path (scaled or original)
const tempDir = $('Set Variables').first().json.temp_dir;
const fs = require('fs');

const scaledPath = `${tempDir}/output_scaled.mp4`;
const originalPath = `${tempDir}/output.mp4`;

let outputPath;
let fileSize;

try {
  const stats = fs.statSync(scaledPath);
  outputPath = scaledPath;
  fileSize = stats.size;
} catch (e) {
  // Scaled file doesn't exist, use original
  const stats = fs.statSync(originalPath);
  outputPath = originalPath;
  fileSize = stats.size;
}

return [{
  json: {
    output_path: outputPath,
    file_size: fileSize
  }
}];

// Parse ffprobe output into structured metadata
const item = $input.first().json;
let ffprobeOutput;

try {
  ffprobeOutput = JSON.parse(item.stdout);
} catch (e) {
  // If ffprobe output parsing fails, return defaults
  return [{
    json: {
      output_path: $('Resolve Output Path').first().json.output_path,
      total_duration: $('Sort Videos').first().json.total_duration,
      file_size_bytes: $('Resolve Output Path').first().json.file_size,
      bitrate: 0,
      video_codec: 'h264',
      resolution: '1920x1080',
      fps: 24
    }
  }];
}

const format = ffprobeOutput.format || {};
const videoStream = (ffprobeOutput.streams || []).find(s => s.codec_type === 'video');

// Parse frame rate safely (e.g., "24/1" -> 24)
let fps = 24;
if (videoStream?.r_frame_rate) {
  const parts = videoStream.r_frame_rate.split('/');
  fps = parts.length === 2 ? Math.round(parseInt(parts[0]) / parseInt(parts[1])) : parseInt(parts[0]);
}

return [{
  json: {
    output_path: $('Resolve Output Path').first().json.output_path,
    total_duration: parseFloat(format.duration) || $('Sort Videos').first().json.total_duration,
    file_size_bytes: parseInt(format.size) || $('Resolve Output Path').first().json.file_size,
    bitrate: parseInt(format.bit_rate) || 0,
    video_codec: videoStream?.codec_name || 'h264',
    resolution: videoStream ? `${videoStream.width}x${videoStream.height}` : '1920x1080',
    fps: fps
  }
}];

// Upload the final combined video to S3 with retry logic
const fs = require('fs');

const vars = $('Set Variables').first().json;
const outputPath = $input.first().json.output_path;
const s3Bucket = $env.S3_BUCKET || 'vdo-gen';
const s3Region = $env.S3_REGION || 'us-east-1';
const s3Key = vars.s3_output_path;

const videoBuffer = fs.readFileSync(outputPath);
const s3Url = `https://${s3Bucket}.s3.${s3Region}.amazonaws.com/${s3Key}`;

let uploaded = false;
let lastError = null;

// Retry up to 3 times with exponential backoff
for (let attempt = 0; attempt < 3; attempt++) {
  try {
    if (attempt > 0) {
      await new Promise(resolve => setTimeout(resolve, 2000 * Math.pow(2, attempt)));
    }

    await this.helpers.httpRequest({
      method: 'PUT',
      url: s3Url,
      headers: {
        'Content-Type': `video/${vars.output_format}`,
        'x-amz-acl': 'public-read',
        'x-amz-meta-execution-id': vars.execution_id,
        'x-amz-meta-scene-count': String($('Sort Videos').first().json.total_videos),
        'x-amz-meta-transition-type': vars.transition_type
      },
      body: videoBuffer,
      encoding: 'arraybuffer',
      timeout: 300000
    });

    uploaded = true;
    break;
  } catch (err) {
    lastError = err;
  }
}

if (!uploaded) {
  throw new Error(`S3 upload failed after 3 attempts: ${lastError?.message || 'Unknown error'}`);
}

return [{
  json: {
    s3_url: s3Url,
    file_size: videoBuffer.length
  }
}];

